PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?bird WHERE {
  ?bird wdt:P9714 ?range .
  FILTER(CONTAINS(?range , 'Africa') || CONTAINS(?range , 'Asia') || CONTAINS(?range , 'Europe') || CONTAINS(?range , 'North America') || CONTAINS(?range , 'South America') || CONTAINS(?range , 'Australia') || CONTAINS(?range , 'Antarctica'))
}
